:root {
  --bg-widget: #1e1e2e;
  --bg-header: #2a2a3d;
  --bg-tag: #2e2e42;
  --bg-tag-active: #6c63ff;
  --bg-progress-track: #2e2e42;
  --bg-progress-fill: #6c63ff;
  --bg-btn-primary: #6c63ff;
  --bg-btn-secondary: #2e2e42;
  --color-label: #a0a0c0;
  --color-digits: #ffffff;
  --color-unit: #6c63ff;
  --color-tag: #a0a0c0;
  --color-tag-active: #ffffff;
  --color-stat-value: #ffffff;
  --color-stat-label: #a0a0c0;
  --color-btn-primary: #ffffff;
  --color-btn-secondary: #a0a0c0;
  --color-marker: #ffffff;
  --color-dot: #4ade80;
  --color-divider: #2e2e42;
  --radius-widget: 20px;
  --radius-tag: 20px;
  --radius-btn: 10px;
  --radius-progress: 6px;
}

.timer-widget {
  background: var(--bg-widget);
  border-radius: var(--radius-widget);
  padding: 24px;
  width: 280px;
  display: flex;
  flex-direction: column;
  gap: 20px;
  margin: 20px auto;
}

.widget-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.widget-label {
  font-size: 11px;
  font-weight: 700;
  letter-spacing: 2px;
  color: var(--color-label);
}

.status-dot {
  width: 10px;
  height: 10px;
  border-radius: 50%;
  background: var(--color-dot);
}

.timer-display {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 4px;
}

.timer-digits {
  font-size: 56px;
  font-weight: 800;
  color: var(--color-digits);
  line-height: 1;
  letter-spacing: -2px;
}

.timer-unit {
  font-size: 13px;
  font-weight: 500;
  color: var(--color-unit);
  letter-spacing: 1px;
}

.progress-track {
  background: var(--bg-progress-track);
  border-radius: var(--radius-progress);
  height: 8px;
  position: relative;
}

.progress-fill {
  background: var(--bg-progress-fill);
  border-radius: var(--radius-progress);
  height: 100%;
  width: 65%;
}

.progress-marker {
  position: absolute;
  top: 50%;
  left: 65%;
  transform: translate(-50%, -50%);
  width: 14px;
  height: 14px;
  border-radius: 50%;
  background: var(--color-marker);
  border: 3px solid var(--bg-progress-fill);
}

.session-tags {
  display: flex;
  gap: 8px;
  flex-wrap: wrap;
}

.tag {
  padding: 6px 14px;
  border-radius: var(--radius-tag);
  font-size: 12px;
  font-weight: 600;
  background: var(--bg-tag);
  color: var(--color-tag);
}

.tag-active {
  background: var(--bg-tag-active);
  color: var(--color-tag-active);
}

.controls {
  display: flex;
  gap: 10px;
}

.btn-secondary {
  flex: 1;
  padding: 12px;
  border-radius: var(--radius-btn);
  border: none;
  background: var(--bg-btn-secondary);
  color: var(--color-btn-secondary);
  font-size: 14px;
  font-weight: 600;
  cursor: pointer;
}

.btn-primary {
  flex: 2;
  padding: 12px;
  border-radius: var(--radius-btn);
  border: none;
  background: var(--bg-btn-primary);
  color: var(--color-btn-primary);
  font-size: 14px;
  font-weight: 700;
  cursor: pointer;
}

.widget-footer {
  display: flex;
  align-items: center;
  justify-content: space-around;
  background: var(--bg-header);
  border-radius: 12px;
  padding: 14px 8px;
}

.stat {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 2px;
}

.stat-value {
  font-size: 18px;
  font-weight: 700;
  color: var(--color-stat-value);
}

.stat-label {
  font-size: 11px;
  font-weight: 500;
  color: var(--color-stat-label);
}

.divider-v {
  width: 1px;
  height: 32px;
  background: var(--color-divider);
}
